// // This module implements a 16-bit SRAM cell with read and write capabilities.
// The SRAM cell consists of a 16-bit data input, a 16-bit data output, a write enable (WE) signal,
// and a read enable (RE) signal. When WE is high and RE is low, the data input should be
// written to the memory. When RE is high and WE is low, the data should be read from the
// memory to the data output.
module sram_cell (
    input wire [15:0] data_in,
    input wire WE,    // Write Enable
    input wire RE,    // Read Enable
    output reg [15:0] data_out
);
    reg [15:0] memory; // 16-bit memory cell

    always @(*) begin
        if (WE && !RE) begin
            memory <= data_in; // Write operation
        end else if (RE && !WE) begin
            data_out <= memory; // Read operation
        end
    end
endmodule

